public class MethodsExample {
    public static void main(String[] args) {
        // Calling methods
        System.out.println("Sum of 5 and 3: " + add(5, 3));
        System.out.println("Sum of 7, 8, and 9: " + add(7, 8, 9));
        System.out.println("Factorial of 5: " + factorial(5));
        sayHello("Alice");

        // Method overloading
        System.out.println("Area of circle (radius 3): " + area(3));
        System.out.println("Area of rectangle (4x5): " + area(4, 5));
    }

    // Method with parameters and return value
    static int add(int a, int b) {
        return a + b;
    }

    // Method overloading
    static int add(int a, int b, int c) {
        return a + b + c;
    }

    // Method with a loop
    static int factorial(int n) {
        int result = 1;
        for (int i = 2; i <= n; i++) {
            result *= i;
        }
        return result;
    }

    // Void method (returns nothing)
    static void sayHello(String name) {
        System.out.println("Hello, " + name + "!");
    }

    // Another overloaded method
    static double area(double radius) {
        return Math.PI * radius * radius;
    }

    static int area(int length, int width) {
        return length * width;
    }
}

